else:
    for k in sorted(set(list(b.keys()) + list(a.keys()))):
        bv = b.get(k, 'MISSING')
        av = a.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k}: {bv} -> {av}')
